import { writeOutput } from "./codegen";

const DOCS_URL = "https://pushinator.com/api";
const PLACEHOLDER_VALUE =
  "CoffeeSafeLocalCoffeeSafeLocalCoffeeSafeLocalCoffeeSaf";

function generateTypeScript(): string {
  const lines: string[] = [
    "// Auto-generated from Pushinator API docs.",
    `// Source: ${DOCS_URL}`,
    "// Regenerate: cd turbo && pnpm -F @vm0/firewalls-generator generate:pushinator",
    "//",
    "// DO NOT EDIT THIS FILE MANUALLY.",
    "",
    'import type { FirewallConfig } from "../contracts/firewalls";',
    "",
    "export const pushinatorFirewall = {",
    '  name: "pushinator",',
    '  description: "Pushinator API",',
    "  placeholders: {",
    `    PUSHINATOR_TOKEN: "${PLACEHOLDER_VALUE}",`,
    "  },",
    "  apis: [",
    "    {",
    '      base: "https://api.pushinator.com",',
    "      auth: {",
    "        headers: {",
    '          Authorization: "Bearer ${{ secrets.PUSHINATOR_TOKEN }}",',
    "        },",
    "      },",
    "      permissions: [],",
    "    },",
    "  ],",
    "} as const satisfies FirewallConfig;",
    "",
  ];
  return lines.join("\n");
}

export async function generate(): Promise<void> {
  console.error("Generating Pushinator firewall config...");
  const ts = generateTypeScript();
  writeOutput("pushinator", ts, import.meta.dirname);
}
